class CloudApiClient(context: Context) {
    private val httpClient = IoTHttpClient(context)
    private val baseUrl = "https://api.example.com"
    private var authToken: String? = null

    fun setAuthToken(token: String) {
        authToken = token
    }

    private fun getAuthHeaders(): Map<String, String> {
        return authToken?.let {
            mapOf("Authorization" to "Bearer $it")
        } ?: emptyMap()
    }

    suspend fun getDevices(): IoTHttpClient.Response {
        return httpClient.get("$baseUrl/devices", getAuthHeaders())
    }

    suspend fun getDevice(deviceId: String): IoTHttpClient.Response {
        return httpClient.get("$baseUrl/devices/$deviceId", getAuthHeaders())
    }

    suspend fun updateDevice(deviceId: String, data: JSONObject): IoTHttpClient.Response {
        return httpClient.putJson("$baseUrl/devices/$deviceId", data, getAuthHeaders())
    }

    suspend fun sendCommand(deviceId: String, command: JSONObject): IoTHttpClient.Response {
        return httpClient.postJson("$baseUrl/devices/$deviceId/commands", command, getAuthHeaders())
    }

    suspend fun deleteDevice(deviceId: String): IoTHttpClient.Response {
        return httpClient.delete("$baseUrl/devices/$deviceId", getAuthHeaders())
    }
}

class LocalIoTDeviceClient(context: Context) {
    private val httpClient = IoTHttpClient(context)

    suspend fun getDeviceStatus(deviceIp: String): IoTHttpClient.Response {
        return httpClient.get("http://$deviceIp/status")
    }

    suspend fun setDeviceState(deviceIp: String, state: JSONObject): IoTHttpClient.Response {
        return httpClient.postJson("http://$deviceIp/state", state)
    }

    suspend fun getDeviceConfig(deviceIp: String): IoTHttpClient.Response {
        return httpClient.get("http://$deviceIp/config")
    }

    suspend fun updateDeviceConfig(deviceIp: String, config: JSONObject): IoTHttpClient.Response {
        return httpClient.putJson("http://$deviceIp/config", config)
    }

    suspend fun rebootDevice(deviceIp: String): IoTHttpClient.Response {
        return httpClient.post("http://$deviceIp/reboot", "")
    }

    suspend fun sendCustomCommand(
        deviceIp: String,
        endpoint: String,
        method: String = "GET",
        body: JSONObject? = null
    ): IoTHttpClient.Response {
        val url = "http://$deviceIp/$endpoint"
        return when (method.uppercase()) {
            "GET" -> httpClient.get(url)
            "POST" -> body?.let { httpClient.postJson(url, it) } ?: httpClient.post(url, "")
            "PUT" -> body?.let { httpClient.putJson(url, it) } ?: httpClient.put(url, "")
            "DELETE" -> httpClient.delete(url)
            else -> throw IllegalArgumentException("Unsupported HTTP method: $method")
        }
    }
